import{_ as i,c as e,o as a,a1 as o}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Copilot認証: OAuthとPAT設定方法 | opencode-mystatus","description":"GitHub Copilotの2つの認証方式（OAuth TokenとFine-grained PAT）の設定方法を学びます。権限問題の解決とクォータクエリを実現します。","frontmatter":{"title":"Copilot認証: OAuthとPAT設定方法 | opencode-mystatus","sidebarTitle":"Copilot認証","subtitle":"Copilot認証設定：OAuth TokenとFine-grained PAT","description":"GitHub Copilotの2つの認証方式（OAuth TokenとFine-grained PAT）の設定方法を学びます。権限問題の解決とクォータクエリを実現します。","tags":["GitHub Copilot","OAuth認証","PAT設定","権限問題"],"prerequisite":["start-quick-start","platforms-copilot-usage"],"order":2},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/advanced/copilot-auth/index.md","filePath":"ja/vbgate/opencode-mystatus/advanced/copilot-auth/index.md"}'),n={name:"ja/vbgate/opencode-mystatus/advanced/copilot-auth/index.md"};function s(l,t,r,d,h,p){return a(),e("div",null,[...t[0]||(t[0]=[o(`<h1 id="copilot認証設定-oauth-tokenとfine-grained-pat" tabindex="-1">Copilot認証設定：OAuth TokenとFine-grained PAT <a class="header-anchor" href="#copilot認証設定-oauth-tokenとfine-grained-pat" aria-label="Permalink to &quot;Copilot認証設定：OAuth TokenとFine-grained PAT&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><ul><li>Copilotの2つの認証方式：OAuth TokenとFine-grained PATを理解</li><li>OAuth Token権限不足の問題を解決</li><li>Fine-grained PATを作成してサブスクリプションタイプを設定</li><li>Copilot Premium Requestsクォータを順調にクエリ</li></ul><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><p>mystatusは<strong>2つのCopilot認証方式</strong>をサポートします：</p><table tabindex="0"><thead><tr><th>認証方式</th><th>説明</th><th>利点</th><th>欠点</th></tr></thead><tbody><tr><td><strong>OAuth Token</strong>（デフォルト）</td><td>OpenCodeログイン時に取得されるGitHub OAuth Token</td><td>追加設定不要、即座に使用可能</td><td>新版OpenCodeのOAuth TokenにはCopilot権限がない場合がある</td></tr><tr><td><strong>Fine-grained PAT</strong>（推奨）</td><td>ユーザーが手動作成したFine-grained Personal Access Token</td><td>安定で信頼性高く、OAuth権限に依存しない</td><td>手動で一度設定が必要</td></tr></tbody></table><p><strong>優先順位ルール</strong>：</p><ol><li>mystatusはFine-grained PATを優先使用（設定されている場合）</li><li>PATが設定されていない場合のみ、OAuth Tokenにフォールバック</li></ol><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-fine-grained-patが設定されているか確認" tabindex="-1">ステップ1：Fine-grained PATが設定されているか確認 <a class="header-anchor" href="#ステップ1-fine-grained-patが設定されているか確認" aria-label="Permalink to &quot;ステップ1：Fine-grained PATが設定されているか確認&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.config/opencode/copilot-quota-token.json</span></span></code></pre></div><h3 id="ステップ2-fine-grained-patを作成-未設定の場合" tabindex="-1">ステップ2：Fine-grained PATを作成（未設定の場合） <a class="header-anchor" href="#ステップ2-fine-grained-patを作成-未設定の場合" aria-label="Permalink to &quot;ステップ2：Fine-grained PATを作成（未設定の場合）&quot;">​</a></h3><ol><li><a href="https://github.com/settings/tokens?type=beta" target="_blank" rel="noreferrer">https://github.com/settings/tokens?type=beta</a> にアクセス</li><li>&quot;Generate new token&quot;をクリック</li><li><strong>Account permissions</strong>で、<strong>Plan</strong>を<strong>Read-only</strong>に設定</li><li>Tokenを生成</li></ol><h3 id="ステップ3-設定ファイルを作成" tabindex="-1">ステップ3：設定ファイルを作成 <a class="header-anchor" href="#ステップ3-設定ファイルを作成" aria-label="Permalink to &quot;ステップ3：設定ファイルを作成&quot;">​</a></h3><p><code>~/.config/opencode/copilot-quota-token.json</code> を作成：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;github_pat_abc123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;username&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;johndoe&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tier&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pro&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>tierフィールドの説明</strong>：</p><ul><li><code>free</code>：Copilot Free（50回/月）</li><li><code>pro</code>：Copilot Pro（300回/月）</li><li><code>pro+</code>：Copilot Pro+（1500回/月）</li><li><code>business</code>：Copilot Business（300回/月）</li><li><code>enterprise</code>：Copilot Enterprise（1000回/月）</li></ul><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>mystatusは2つのCopilot認証方式をサポート：</p><ol><li><strong>OAuth Token</strong>（デフォルト）：自動取得、ただし権限問題がある可能性</li><li><strong>Fine-grained PAT</strong>（推奨）：手動設定、安定で信頼性高い</li></ol><p>推奨されるFine-grained PATの設定手順：</p><ol><li>GitHub SettingsでFine-grained PATを作成</li><li>&quot;Plan: Read&quot;権限を設定</li><li>GitHubユーザー名とサブスクリプションタイプを記録</li><li><code>~/.config/opencode/copilot-quota-token.json</code> 設定ファイルを作成</li><li>設定を検証</li></ol><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>Copilot認証戦略エントリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/copilot.ts" target="_blank" rel="noreferrer"><code>plugin/lib/copilot.ts</code></a></td><td>481-524</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details>`,26)])])}const g=i(n,[["render",s]]);export{c as __pageData,g as default};
